(() => {
  'use strict';
  if (window.__pcbw_adventureInit) return;
  window.__pcbw_adventureInit = true;

  const NS = '__pcbw_adventure';

  const SCENES = {
    tavern: {
      name: 'The Driftwood Tavern',
      description: 'A warmly lit tavern at the crossroads. Firelight dances on oak walls.',
      lore: 'The Driftwood Tavern has stood for three centuries, built from the hull of a legendary ship.'
    },
    forest: {
      name: 'The Whispering Woods',
      description: 'Ancient trees loom overhead, their leaves murmuring secrets.',
      lore: 'The Whispering Woods are said to remember every traveler who has passed through them.'
    },
    ruins: {
      name: 'The Sunken Archive',
      description: 'Crumbling stone halls descend into darkness. Glowing runes line the walls.',
      lore: 'The Sunken Archive was once the greatest library of the Old Kingdom, lost to a cataclysm.'
    },
    market: {
      name: 'The Lantern Market',
      description: 'A bustling night market lit by hundreds of floating lanterns.',
      lore: 'The Lantern Market appears only on nights when the twin moons align, drawing merchants from across the realm.'
    },
    summit: {
      name: 'The Windspire Summit',
      description: 'A windswept peak above the clouds. The world stretches endlessly below.',
      lore: 'Legend says those who reach the Windspire Summit can hear the voice of the world itself.'
    }
  };

  function ensureState() {
    if (!oc.thread.customData) oc.thread.customData = {};
    if (!oc.thread.customData[NS]) {
      oc.thread.customData[NS] = {
        currentScene: 'tavern',
        visitedScenes: ['tavern'],
        inventory: [],
        questLog: [],
        loreDiscovered: ['tavern'],
        turnCount: 0
      };
    }
    return oc.thread.customData[NS];
  }

  function buildSceneContext(state) {
    const scene = SCENES[state.currentScene];
    if (!scene) return '';
    let ctx = '[CURRENT SCENE: ' + scene.name + ' — ' + scene.description + ']';
    if (state.loreDiscovered.includes(state.currentScene)) {
      ctx += '\n[SCENE LORE: ' + scene.lore + ']';
    }
    if (state.inventory.length > 0) {
      ctx += '\n[INVENTORY: ' + state.inventory.join(', ') + ']';
    }
    if (state.questLog.length > 0) {
      ctx += '\n[ACTIVE QUESTS: ' + state.questLog.slice(-3).join('; ') + ']';
    }
    ctx += '\n[TURN: ' + state.turnCount + ', SCENES VISITED: ' + state.visitedScenes.length + '/' + Object.keys(SCENES).length + ']';
    return ctx;
  }

  function processCommand(text) {
    const state = ensureState();
    const lower = (text || '').toLowerCase().trim();

    if (lower.startsWith('/go ')) {
      const dest = lower.substring(4).trim();
      if (SCENES[dest]) {
        state.currentScene = dest;
        if (!state.visitedScenes.includes(dest)) {
          state.visitedScenes.push(dest);
        }
        if (!state.loreDiscovered.includes(dest)) {
          state.loreDiscovered.push(dest);
        }
      }
    } else if (lower.startsWith('/take ')) {
      const item = text.trim().substring(6).trim();
      if (item && state.inventory.length < 15) {
        state.inventory.push(item);
      }
    } else if (lower.startsWith('/quest ')) {
      const quest = text.trim().substring(7).trim();
      if (quest && state.questLog.length < 10) {
        state.questLog.push(quest);
      }
    } else if (lower === '/look') {
      // Just triggers re-render of scene context
    } else if (lower === '/map') {
      // Handled by the AI via context
    }
  }

  oc.thread.on('MessageAdded', function() {
    try {
      const state = ensureState();
      const msgs = oc.thread.messages;
      if (!msgs || msgs.length === 0) return;
      const last = msgs[msgs.length - 1];
      if (last.author !== 'user') return;

      state.turnCount++;
      const text = (last.content || '').trim();
      if (text.startsWith('/')) processCommand(text);

      var sceneCtx = buildSceneContext(state);
      if (oc.character && oc.character.reminderMessage !== undefined) {
        var baseReminder = 'You are narrating an interactive adventure. Stay in the current scene. Describe the environment vividly. React to player actions with consequences. Use discovered lore naturally. Track inventory mentions. Write in second person present tense. Keep responses atmospheric and immersive.';
        oc.character.reminderMessage = baseReminder + '\n' + sceneCtx;
      }
    } catch (e) {
      console.warn('[AdventureBot] MessageAdded handler error:', e);
    }
  });
})();
